 93→extern "C" auto sc_main(const int argc, char* argv[]) -> int
 94→try {
 95→  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
 96→  spdlog::set_pattern("[%^%l%$] %v");
 97→
 98→  const auto args = [&] {
 99→    struct args
100→    {
101→      std::string dump_wb_pcs{};
102→      std::string elf_file{};
103→      std::optional<uint16_t> jdtm_rbb_port = std::nullopt;
104→      bool trace = false;
105→      bool memmap = false;
106→      std::string trace_file = "dump.vcd";
107→      std::string mace;
108→    } args;
109→
110→    auto p = parser{};
111→    p.shortflag('h', [] {
112→      print_help();
113→      exit(0);
114→    });
115→    p.longopt("jdtm-rbb-port", [&](const std::string_view s) {
116→      if (auto n = to_int<uint16_t>(s); n) {
117→        args.jdtm_rbb_port = *n;
118→      } else {
119→        throw std::runtime_error("invalid number for --jdtm-rbb-port: "
120→                                 + std::string{s});
121→      }
122→    });
123→    p.longflag("trace", [&] { args.trace = true; });
124→    p.longopt("trace-file",
125→              [&](const std::string_view s) { args.trace_file = s; });
126→    p.longopt("mace", [&](const std::string_view s) { args.mace = s; });
127→    p.longopt("log-level", [](const std::string_view s) {
128→      if (auto n = to_int<uint16_t>(s); n) {
129→        *n = std::min(*n, (uint16_t) SPDLOG_LEVEL_OFF);
130→        spdlog::set_level(static_cast<spdlog::level::level_enum>(*n));
131→      } else {
132→        throw std::runtime_error("invalid number for --log-level: "
133→                                 + std::string{s});
134→      }
135→    });
136→    p.longflag("help", [] {
137→      print_help();
138→      exit(0);
139→    });
140→    p.longflag("version", [] {
141→      print_version();
142→      exit(0);
143→    });
144→    p.longflag("print-memmap", [&] { args.memmap = true; });
145→    p.longflag("print-config", [] {
146→      print_cpu_configuration();
147→      exit(0);
148→    });
149→    p.posarg([&](const std::string_view s) { args.elf_file = s; });
150→    p.parse(std::vector<std::string_view>(argv, argv + argc));
151→    return args;
152→  }();
153→
154→  print_version();
155→
156→  // output ACE, ACERVV support version
157→  if (get_libaceasim_version)
158→    spdlog::info("ACE and ACERVV support version: {}",
159→                 get_libaceasim_version());
160→  else
161→    spdlog::info(
162→      "ACE and ACERVV support version: The CPU configuration does not include libaceasim support.");
163→
164→  // systemc and cci init
165→  auto broker = cci_utils::broker{"global_broker"};
166→  cci::cci_register_broker(broker);
167→
168→  sc_core::sc_set_time_resolution(1.0, sc_core::SC_PS);
169→  const auto time_resolution = sc_core::sc_get_time_resolution();
170→  spdlog::debug("Using time resolution: {}", time_resolution.to_string());
171→
172→  // run simulation
173→  const auto do_sim = [&]<typename CPU>() -> int {
174→    simulator<CPU, platform<platform_config<CPU>>> sim{"sim"};
175→
176→    if (args.memmap) {
177→      sim.platform.interconnect.dump_region();
178→      return 0;
179→    }
180→
181→    //
182→    // End of elaboration
183→    //
184→
185→    sc_core::sc_start(sc_core::SC_ZERO_TIME);
186→
187→    const auto t0 = std::chrono::steady_clock::now();
188→
189→    if (args.trace)
190→      sim.enable_trace_logging(args.trace_file);
191→
192→    if (!args.elf_file.empty())
193→      sim.load_elf(args.elf_file);
194→
195→    if (args.jdtm_rbb_port)
196→      sim.init_debug_port(args.jdtm_rbb_port.value());
197→
198→    if (!args.jdtm_rbb_port && args.elf_file.empty())
199→      throw std::runtime_error("Required arg : program or --jdtm-rbb-port");
200→
201→    sim.reset();
202→    int exit_code = sim.run();
203→
204→    sim.cpu.final();
205→
206→    const auto t1 = std::chrono::steady_clock::now();
207→
208→    if (args.trace)
209→      sim.close_trace();
210→
211→    const auto cycles = sim.get_cycles();
212→    spdlog::info("{} cycles simulated", cycles);
213→    if (cycles > 0) {
214→      const auto ms =
215→        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
216→      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
217→                   ms.count() % 1000,
218→                   double(cycles) / double(ms.count()) * 1000.0);
219→    }
220→    return exit_code;
221→  };
222→
223→  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
224→
225→} catch (const std::exception& e) {
226→  spdlog::critical("fatal exception: {}\n", e.what());
227→  std::exit(EXIT_FAILURE);
228→} catch (...) {
229→  std::terminate();
230→}
