 20→class parser
 21→{
 22→public:
 23→  using string_handler = std::function<auto(std::string_view)->void>;
 24→  using flag_handler = std::function<auto()->void>;
 25→  using handler = std::variant<string_handler, flag_handler>;
 26→
 27→  std::unordered_map<std::string_view, handler> longopts;
 28→  std::unordered_map<char, handler> shortopts;
 29→
 30→  string_handler posarg_handler = [](auto) {};
 31→  string_handler unknown_handler = [](const std::string_view s) {
 32→    throw std::runtime_error{"Unrecognized option: " + std::string{s}};
 33→  };
 34→
 35→  auto longopt(const std::string_view k, const string_handler& h) -> parser&
 36→  {
 37→    longopts.emplace(k, h);
 38→    return *this;
 39→  }
 40→
 41→  auto longflag(const std::string_view k, const flag_handler& h) -> parser&
 42→  {
 43→    longopts.emplace(k, h);
 44→    return *this;
 45→  }
 46→
 47→  auto shortopt(const char c, const string_handler& h) -> parser&
 48→  {
 49→    shortopts.emplace(c, h);
 50→    return *this;
 51→  }
 52→
 53→  auto shortflag(const char c, const flag_handler& h) -> parser&
 54→  {
 55→    shortopts.emplace(c, h);
 56→    return *this;
 57→  }
 58→
 59→  auto posarg(const string_handler& h) -> parser&
 60→  {
 61→    posarg_handler = h;
 62→    return *this;
 63→  }
 64→
 65→  auto unknown(const string_handler& h) -> parser&
 66→  {
 67→    unknown_handler = h;
 68→    return *this;
 69→  }
 70→
 71→  void parse(const std::span<const std::string_view> args) const
 72→  {
 73→    if (args.empty())
 74→      return;
 75→
 76→    for (auto it = args.begin() + 1; it != args.end(); ++it) {
 77→      const auto s = *it;
 78→
 79→      if (s == "--") {
 80→        for (it = std::next(it); it != args.end(); ++it)
 81→          posarg_handler(*it);
 82→        break;
 83→      } else if (s.starts_with("--")) {
 84→        const auto eq = s.find('=', 2);
 85→        const auto key =
 86→          eq == std::string::npos ? s.substr(2, eq) : s.substr(2, eq - 2);
 87→
 88→        const auto hit = longopts.find(key);
 89→        if (hit == std::end(longopts)) {
 90→          unknown_handler(s.substr(0, eq));
 91→          continue;
 92→        }
 93→
 94→        std::visit(overload{[&](const flag_handler& f) { f(); },
 95→                            [&](const string_handler& f) {
 96→                              if (eq != std::string::npos) { // --key=value
 97→                                f(s.substr(eq + 1));
 98→                              } else if (++it != args.end()) { // --key value
 99→                                f(*it);
100→                              } else {
101→                                throw std::runtime_error{"No value given for --"
102→                                                         + std::string{key}};
103→                              }
104→                            }},
105→                   hit->second);
106→      } else if (s.starts_with("-")) {
107→        for (auto cit = s.begin() + 1; cit != s.end(); ++cit) {
108→          const char c = *cit;
109→          const auto hit = shortopts.find(c);
110→
111→          if (hit == std::end(shortopts)) {
112→            unknown_handler(std::string("-") + c);
113→            continue;
114→          }
115→
116→          std::visit(overload{[&](const flag_handler& f) { f(); },
117→                              [&](const string_handler& f) {
118→                                if (const auto value = std::next(cit);
119→                                    value != s.end()) { // -ovalue
120→                                  f(s.substr(value - s.begin()));
121→                                  cit = std::prev(s.end());
122→                                } else if (++it != args.end()) { // -o value
123→                                  f(*it);
124→                                } else {
125→                                  throw std::runtime_error{
126→                                    "No value given for -" + std::string{c}};
127→                                }
128→                              }},
129→                     hit->second);
130→        }
131→      } else {
132→        posarg_handler(s);
133→      }
134→    }
135→  }
136→};
137→
138→#endif
