#include <stdio.h>

int main(void)
{
  unsigned long hartid;
  __asm__("csrr %0, mhartid" : "=r"(hartid));

  static _Bool flag = 0;
  while (__atomic_test_and_set(&flag, __ATOMIC_SEQ_CST))
    ;
  printf("hello world from hart %lu!\n", hartid);
  __atomic_clear(&flag, __ATOMIC_SEQ_CST);
  return 0;
}

