class RecorderBase:
    def __init__(self, cpu) -> None:
        self.cpu = cpu

    def get_signal(self, s: str) -> int:
        return getattr(self.cpu, s)

    @abstractmethod
    def record(self, idx: Optional[int]) -> None:
        pass


class SignalRecorder(RecorderBase):
    def __init__(self, cpu, signal_names: List[str], log_file: str) -> None:
        super().__init__(cpu)
        self.signal_names = signal_names
        self.fout = open(log_file, "w")
        self.fout.write(",".join(self.signal_names) + "\n")

    def record(self, _idx=None) -> None:
        signals = []
        for n in self.signal_names:
            v = self.get_signal(n)
            s = hex(v) if v > 1 else str(v)

from importlib import import_module


class Vsim:
    def __init__(self, cpu: str) -> None:
        try:
            self.pymodule = import_module(f".lib.sim_{cpu}", "vsim")
            self.simulator_class = getattr(self.pymodule, f"simulator_{cpu}")
        except:
            raise ValueError(f"Unsupported cpu : {cpu} , please check --cpu option")
        self.simulator = self.simulator_class(cpu)

    def set_log_level(self, level: int) -> None:
        # 1: DEBUG, 2: INFO, 3: WARN
        self.pymodule.set_log_level(level)

    def get_version(self) -> str:
        return (
            "Copyright (C) 2013-2025 Andes Technology Corporation. All rights reserved.\nAndesCycle version : "
            + self.pymodule.get_version()
        )

    def get_libaceasim_version(self) -> str:
        return self.pymodule.get_libaceasim_version()

    def get_config(self) -> str:
        return self.pymodule.get_config()

    def __getattr__(self, name: str):
        """
        It forwards the call if name is not found in Vsim.
        """
        return getattr(self.simulator, name)

