174→    simulator<CPU, platform<platform_config<CPU>>> sim{"sim"};
175→
176→    if (args.memmap) {
177→      sim.platform.interconnect.dump_region();
178→      return 0;
179→    }
180→
181→    //
182→    // End of elaboration
183→    //
184→
185→    sc_core::sc_start(sc_core::SC_ZERO_TIME);
186→
187→    const auto t0 = std::chrono::steady_clock::now();
188→
189→    if (args.trace)
190→      sim.enable_trace_logging(args.trace_file);
191→
192→    if (!args.elf_file.empty())
193→      sim.load_elf(args.elf_file);
194→
195→    if (args.jdtm_rbb_port)
196→      sim.init_debug_port(args.jdtm_rbb_port.value());
197→
198→    if (!args.jdtm_rbb_port && args.elf_file.empty())
199→      throw std::runtime_error("Required arg : program or --jdtm-rbb-port");
200→
201→    sim.reset();
202→    int exit_code = sim.run();
203→
204→    sim.cpu.final();
205→
206→    const auto t1 = std::chrono::steady_clock::now();
207→
208→    if (args.trace)
209→      sim.close_trace();
210→
211→    const auto cycles = sim.get_cycles();
212→    spdlog::info("{} cycles simulated", cycles);
213→    if (cycles > 0) {
214→      const auto ms =
215→        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
216→      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
217→                   ms.count() % 1000,
218→                   double(cycles) / double(ms.count()) * 1000.0);
219→    }
220→    return exit_code;
221→  };
222→
223→  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
224→
225→} catch (const std::exception& e) {
226→  spdlog::critical("fatal exception: {}\n", e.what());
227→  std::exit(EXIT_FAILURE);
228→} catch (...) {
229→  std::terminate();
230→}
