import re
import sys


def parse_functions_from_disassembly(disassembly_filename):
    functions = []
    current_function = None
    function_pattern = re.compile(r"^([0-9a-fA-F]+)\s+<([^>]+)>:")
    pc_pattern = re.compile(r"^\s*([0-9a-fA-F]+):\s")
    with open(disassembly_filename, "r") as disasm_file:
        for line in disasm_file:
            function_match = function_pattern.match(line)
            pc_match = pc_pattern.match(line)
            if function_match:
                # Start of a new function
                if current_function:
                    functions.append(current_function)
                current_function = {
                    "name": function_match.group(2),
                    "start": int(function_match.group(1), 16),
                    "end": None,
                    "pcs": [],
                }
            elif pc_match and current_function:
                # Parse the PC within a function
                current_function["pcs"].append(int(pc_match.group(1), 16))
        # Append the last function
        if current_function:
            functions.append(current_function)
    # Calculate function end addresses
    for i in range(len(functions) - 1):
        functions[i]["end"] = functions[i + 1]["start"] - 1
    functions[-1]["end"] = None  # Last function goes to the end
    return functions


def find_function_for_pc(pc, functions):
    for func in functions:
        if func["start"] <= pc and (func["end"] is None or pc <= func["end"]):
            return func["name"]
    return None


def create_function_trace_log(functions):
    last_function_name = None
    pc_pattern = re.compile(r"\[trace\] PC: ([0-9a-fA-F]+)")
    function_cycle_durations = {}

    for line in sys.stdin:
        match = pc_pattern.search(line)
        if match:
            pc = int(match.group(1), 16)
            function_name = find_function_for_pc(pc, functions)
            if function_name != last_function_name:
                if function_name:
                    print(f"{hex(pc)} : {function_name}")
                else:
                    print(f"PC {hex(pc)} does not belong to any known function")
                last_function_name = function_name

            if function_name not in function_cycle_durations:
                function_cycle_durations[function_name] = 0
            function_cycle_durations[function_name] += 1

    # Sort the dictionary by values in descending order
    sorted_keys = sorted(
        function_cycle_durations, key=function_cycle_durations.get, reverse=True
    )

    # Print the keys in sorted order
    print("\n\n\n===== Function and its duration Cycles =====\n")
    total = 0
    for key in sorted_keys:
        cycles = function_cycle_durations[key]
        total += cycles
        print(key, " : ", cycles)

    print("\nTotal cycles : ", total)


def main():
    if len(sys.argv) < 2:
        print("Usage: python func_trace.py <disassembly_filename>")
        sys.exit(1)

    disassembly_filename = sys.argv[1]

    # Parse the function information from the disassembled file
    functions = parse_functions_from_disassembly(disassembly_filename)

    # Create the function trace log (reading from stdin line by line)
    create_function_trace_log(functions)


if __name__ == "__main__":
    main()

